import { ComponentType } from '../../../cms/registries/types/propTypes';
import { ProductCarousalWrapperProps, CarousalType } from '../../../components/ProductCarousalWrapper/types/propsType';
import { CMSDataType } from '../../../utils/common';
const transformProductCarousal = (data: CMSDataType): ProductCarousalWrapperProps => {
  const productCarousal = Array.isArray(data?.product_carousel) ? data?.product_carousel[0] : data?.product_carousel;
  const products = productCarousal?.products?.map((p: CMSDataType) => ({
    productId: p.product_id,
    isBundle: p.is_bundle,
  }));
  const { end_time: endTime, title } = productCarousal?.countdowntimer ?? {};
  const mapCarousalType = (type?: string): CarousalType => {
    switch (type) {
      case CarousalType.Vertical:
        return CarousalType.Vertical;
      default:
        return CarousalType.Horizontal;
    }
  };

  return {
    componentType: ComponentType.product_carousel,
    products: products ?? [],
    title: productCarousal.display_title,
    type: mapCarousalType(productCarousal.type),
    backgroundColor: productCarousal.background_color,
    themeColor: productCarousal.theme_color?.color,
    countdownTimer: { endTime: endTime, title },
  };
};

export default transformProductCarousal;
