import { Logger } from '@nextgen-web-framework/core';
import { componentTransformerRegistry as UiComponentTransformerRegistry } from '@commerce-webcomponents/ui';
import logObject from '../../../logObject';
import { CMSDataType } from '../../utils/common';
import { AbstractComponentPropTypes } from '../registries';
import componentTransformerRegistry from '../registries/componentTransformerRegistry';
import { ComponentType } from '../registries/types/propTypes';

const transformComponent = <S extends AbstractComponentPropTypes>(data: CMSDataType, componentKey: string): S => {
  const logger = Logger.getInstance(logObject('TransformComponent Ui-Composite'));
  try {
    if (Object.hasOwn(componentTransformerRegistry, componentKey)) {
      return componentTransformerRegistry[componentKey](data) as S;
    } else if (Object.hasOwn(UiComponentTransformerRegistry, componentKey)) {
      return UiComponentTransformerRegistry[componentKey](data) as S;
    }
    return componentTransformerRegistry[ComponentType.default]({}) as S;
  } catch (err) {
    logger.error(`Error transforming ${componentKey}`, err);
    return componentTransformerRegistry[ComponentType.default]({}) as S;
  }
};

export default transformComponent;
