import { ComponentType } from '../../../cms/registries/types/propTypes';
import { ProductCarousalWrapperProps, CarousalType } from '../../../components/ProductCarousalWrapper/types/propsType';
import { CMSDataType } from '../../../utils/common';
const transformAPointProductCarousal = (data: CMSDataType): ProductCarousalWrapperProps => {
  const productCarousal = Array.isArray(data?.a_point_product_carousel)
    ? data?.a_point_product_carousel[0]
    : data?.a_point_product_carousel;
  const products = productCarousal?.products?.map((p: CMSDataType) => ({
    productId: p.product_id,
    isBundle: p.is_bundle,
  }));

  return {
    componentType: ComponentType.a_point_product_carousel,
    products: products ?? [],
    title: productCarousal.display_title,
    type: CarousalType.APointCatalog,
  };
};

export default transformAPointProductCarousal;
