import { Logger } from '@nextgen-web-framework/core';
import { ErrorCard, Errors, componentRegistry as UiComponentRegistry } from '@commerce-webcomponents/ui';
import { useNextgenRouter } from '@nextgen-web-framework/all';
import logObject from '../../../logObject';
import { componentRegistry, transformComponent } from '../../cms';
import { ComponentType } from '../../cms/registries/types/propTypes';
import DefaultComponent from '../defaultComponent/DefaultComponent';
import type { CmsComponentProps } from './types/propTypes';

const CmsComponent = ({ componentKey, data, ...componentRestProps }: CmsComponentProps) => {
  const logger = Logger.getInstance(logObject('CmsComponent'));
  const router = useNextgenRouter();
  try {
    const componentProps = transformComponent(data, componentKey);
    const { componentType, ...rest } = componentProps;
    if (componentType == ComponentType.error_page) {
      return <ErrorCard type={Errors.NotFound} onActionClick={() => router.push('/')} />;
    }
    // eslint-disable-next-line @typescript-eslint/naming-convention
    let ResolvedComponent: React.ElementType = () => <></>;
    if (Object.hasOwn(componentRegistry, componentType)) {
      ResolvedComponent = componentRegistry[componentType];
    } else if (Object.hasOwn(UiComponentRegistry, componentType)) {
      ResolvedComponent = UiComponentRegistry[componentType];
    }
    return (
      <>
        <ResolvedComponent {...rest} {...componentRestProps} />
      </>
    );
  } catch (err) {
    logger.error(`Failed Rendering CMS Component ${componentKey}`, err);
    return <DefaultComponent />;
  }
};

export default CmsComponent;
